# Define tools whose outputs map 1:1 to UI components
FLIGHT_CARD_TOOL = {
    "name": "render_flight_cards",
    "description": "Display a list of flight options as interactive cards the user can book.",
    "input_schema": {
        "type": "object",
        "properties": {
            "flights": {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "id":         {"type": "string"},
                        "airline":    {"type": "string"},
                        "flight_no":  {"type": "string"},
                        "departs":    {"type": "string", "description": "ISO 8601 datetime"},
                        "arrives":    {"type": "string", "description": "ISO 8601 datetime"},
                        "stops":      {"type": "integer"},
                        "duration_m": {"type": "integer", "description": "Duration in minutes"},
                        "price_usd":  {"type": "number"},
                        "cabin":      {"type": "string", "enum": ["economy","business","first"]},
                    },
                    "required": ["id","airline","flight_no","departs","arrives","price_usd"],
                },
            },
            "sort_by": {"type": "string", "enum": ["price","duration","departs"], "default": "price"},
        },
        "required": ["flights"],
    },
}

DATA_TABLE_TOOL = {
    "name": "render_data_table",
    "description": "Display structured data as a sortable, filterable table.",
    "input_schema": {
        "type": "object",
        "properties": {
            "columns": {
                "type": "array",
                "items": {"type": "object",
                          "properties": {"key": {"type": "string"}, "label": {"type": "string"},
                                         "sortable": {"type": "boolean"}},
                          "required": ["key","label"]},
            },
            "rows": {"type": "array", "items": {"type": "object"}},
            "title": {"type": "string"},
        },
        "required": ["columns","rows"],
    },
}

FORM_TOOL = {
    "name": "render_form",
    "description": "Display an interactive form for collecting structured user input.",
    "input_schema": {
        "type": "object",
        "properties": {
            "title":       {"type": "string"},
            "description": {"type": "string"},
            "fields": {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "name":     {"type": "string"},
                        "label":    {"type": "string"},
                        "type":     {"type": "string", "enum": ["text","number","date","select","checkbox"]},
                        "required": {"type": "boolean"},
                        "options":  {"type": "array", "items": {"type": "string"}},
                    },
                    "required": ["name","label","type"],
                },
            },
            "submit_label": {"type": "string", "default": "Submit"},
        },
        "required": ["fields"],
    },
}

UI_TOOLS = [FLIGHT_CARD_TOOL, DATA_TABLE_TOOL, FORM_TOOL]

// ComponentDispatcher.tsx - maps tool names to React components
import { FlightCards }  from "./FlightCards";
import { DataTable }    from "./DataTable";
import { DynamicForm }  from "./DynamicForm";

const COMPONENT_MAP: Record<string, React.ComponentType<any>> = {
  render_flight_cards: FlightCards,
  render_data_table:   DataTable,
  render_form:         DynamicForm,
};

export function ComponentDispatcher({
  component,
  props,
  toolId,
}: {
  component: string;
  props: unknown;
  toolId: string;
}) {
  const Component = COMPONENT_MAP[component];
  if (!Component) {
    return (
      <pre className="text-xs text-slate-400 bg-slate-900 rounded p-2 overflow-x-auto">
        {JSON.stringify(props, null, 2)}
      </pre>
    );
  }
  return <Component key={toolId} {...(props as object)} />;
}

// FlightCards.tsx - rendered when model calls render_flight_cards
import { useState } from "react";

interface Flight {
  id: string; airline: string; flight_no: string;
  departs: string; arrives: string; stops: number;
  duration_m: number; price_usd: number; cabin: string;
}

export function FlightCards({ flights, sort_by = "price" }: { flights: Flight[]; sort_by?: string }) {
  const [sort, setSort]   = useState(sort_by);
  const [filter, setFilter] = useState<string | null>(null);

  const sorted = [...flights]
    .filter(f => filter === "nonstop" ? f.stops === 0 : true)
    .sort((a, b) => {
      if (sort === "price")    return a.price_usd - b.price_usd;
      if (sort === "duration") return (a.duration_m ?? 0) - (b.duration_m ?? 0);
      return new Date(a.departs).getTime() - new Date(b.departs).getTime();
    });

  const fmt = (iso: string) => new Date(iso).toLocaleTimeString([], {hour:"2-digit",minute:"2-digit"});
  const dur = (m: number)   => `${Math.floor(m/60)}h ${m%60}m`;

  return (
    <div className="my-2 rounded-xl border border-slate-700 overflow-hidden">
      {/* Filter bar */}
      <div className="flex gap-3 px-4 py-2 bg-slate-900 border-b border-slate-700 text-xs">
        <select value={sort} onChange={e => setSort(e.target.value)}
                className="bg-transparent text-slate-300 outline-none cursor-pointer">
          <option value="price">Sort: Price</option>
          <option value="duration">Sort: Duration</option>
          <option value="departs">Sort: Departs</option>
        </select>
        <button onClick={() => setFilter(f => f === "nonstop" ? null : "nonstop")}
                className={`px-2 py-0.5 rounded-full border ${
                  filter === "nonstop"
                    ? "border-indigo-500 text-indigo-300 bg-indigo-950"
                    : "border-slate-600 text-slate-400"}`}>
          Non-stop only
        </button>
      </div>
      {/* Cards */}
      {sorted.map(f => (
        <div key={f.id} className="flex items-center gap-4 px-4 py-3 border-b border-slate-800
                                    hover:bg-slate-800/50 transition-colors">
          <div className="flex-1 min-w-0">
            <p className="font-semibold text-slate-200 text-sm">
              {f.airline} {f.flight_no}
              <span className="ml-2 text-slate-400 font-normal text-xs">
                {fmt(f.departs)} &#8594; {fmt(f.arrives)}
              </span>
            </p>
            <p className="text-xs text-slate-500 mt-0.5">
              {f.stops === 0 ? "Non-stop" : `${f.stops} stop${f.stops > 1 ? "s" : ""}`}
              {f.duration_m ? ` · ${dur(f.duration_m)}` : ""}
              {" · "}{f.cabin}
            </p>
          </div>
          <div className="text-right shrink-0">
            <p className="text-indigo-300 font-bold">${f.price_usd}</p>
            <button className="mt-1 text-xs bg-indigo-600 hover:bg-indigo-500 text-white
                               px-3 py-1 rounded-lg">
              Book
            </button>
          </div>
        </div>
      ))}
    </div>
  );
}

// AssistantMessage.tsx - renders mixed text + UI component output
export function AssistantMessage({ message }: { message: AgentMessage }) {
  return (
    <div className="space-y-2">
      {/* Text portion */}
      {message.text && (
        <div className="text-slate-200 text-sm leading-relaxed">
          {message.text}
        </div>
      )}
      {/* UI components rendered inline */}
      {message.ui?.map(comp => (
        <ComponentDispatcher
          key={comp.toolId}
          component={comp.component}
          props={comp.props}
          toolId={comp.toolId}
        />
      ))}
    </div>
  );
}

// In ChatView, the SSE stream emits a "ui_component" event alongside "text":
// { type: "ui_component", component: "render_flight_cards", props: {...}, tool_id: "..." }
// On receiving it, append to the current assistant message's ui array.

// DynamicForm.tsx - renders when model calls render_form
export function DynamicForm({
  title,
  description,
  fields,
  submit_label = "Submit",
  onSubmit,
}: {
  title?: string;
  description?: string;
  fields: Array<{name: string; label: string; type: string; required?: boolean; options?: string[]}>;
  submit_label?: string;
  onSubmit?: (values: Record<string, string>) => void;
}) {
  const [values, setValues] = useState<Record<string, string>>({});

  const set = (name: string, val: string) => setValues(v => ({ ...v, [name]: val }));

  return (
    <div className="my-2 rounded-xl border border-slate-700 bg-slate-800/50 p-4">
      {title && <h3 className="text-slate-200 font-semibold mb-1">{title}</h3>}
      {description && <p className="text-slate-400 text-sm mb-3">{description}</p>}
      <div className="space-y-3">
        {fields.map(f => (
          <div key={f.name}>
            <label className="text-xs text-slate-400 block mb-1">
              {f.label}{f.required && <span className="text-red-400 ml-0.5">*</span>}
            </label>
            {f.type === "select" ? (
              <select value={values[f.name] ?? ""} onChange={e => set(f.name, e.target.value)}
                      className="w-full bg-slate-900 border border-slate-600 text-slate-200
                                 rounded-lg px-3 py-2 text-sm outline-none focus:border-indigo-500">
                <option value="">Select...</option>
                {f.options?.map(o => <option key={o} value={o}>{o}</option>)}
              </select>
            ) : (
              <input type={f.type} value={values[f.name] ?? ""}
                     onChange={e => set(f.name, e.target.value)}
                     className="w-full bg-slate-900 border border-slate-600 text-slate-200
                                rounded-lg px-3 py-2 text-sm outline-none focus:border-indigo-500"
              />
            )}
          </div>
        ))}
      </div>
      <button
        onClick={() => onSubmit?.(values)}
        className="mt-4 bg-indigo-600 hover:bg-indigo-500 text-white text-sm px-4 py-2 rounded-lg"
      >
        {submit_label}
      </button>
    </div>
  );
}

// Validate with Zod before rendering
import { z } from "zod";

const FlightSchema = z.object({
  id:         z.string(),
  airline:    z.string().max(50),
  flight_no:  z.string().max(10),
  departs:    z.string().datetime(),
  arrives:    z.string().datetime(),
  stops:      z.number().int().min(0).max(10),
  duration_m: z.number().int().positive().optional(),
  price_usd:  z.number().positive().max(100_000),
  cabin:      z.enum(["economy","business","first"]),
});

const FlightCardsSchema = z.object({
  flights:  z.array(FlightSchema).max(20),
  sort_by:  z.enum(["price","duration","departs"]).optional(),
});

// In ComponentDispatcher, before rendering:
function validateProps(component: string, props: unknown): unknown {
  if (component === "render_flight_cards") {
    return FlightCardsSchema.parse(props);   // throws ZodError on invalid input
  }
  return props;  // other components not yet validated
}

// In the SSE event handler, accumulate partial tool input
const toolBuffers: Record<number, { name: string; raw: string }> = {};

if (evt.type === "content_block_start" && evt.content_block.type === "tool_use") {
  toolBuffers[evt.index] = { name: evt.content_block.name, raw: "" };
  // Show skeleton immediately
  appendSkeletonComponent(evt.content_block.name);
}
if (evt.type === "content_block_delta" && evt.delta.type === "input_json_delta") {
  if (toolBuffers[evt.index]) toolBuffers[evt.index].raw += evt.delta.partial_json;
}
if (evt.type === "content_block_stop" && toolBuffers[evt.index]) {
  const { name, raw } = toolBuffers[evt.index];
  const props = JSON.parse(raw || "{}");
  replaceSkeletonWithComponent(name, props);   // swap skeleton for real component
  delete toolBuffers[evt.index];
}
